svg.script:
//
(function(){
 var NS="http://www.w3.org/2000/svg", D=document;
 function mk(t,a){var e=D.createElementNS(NS,t);if(a)for(var k in a)e.setAttribute(k,a[k]);return e;}
 function put(p,t,a){var e=mk(t,a);p.appendChild(e);return e;}
 var DEG=Math.PI/180;

 // geometry
 var CX=334, CY=398, RSRC=224, SDD=448, FAN=34*DEG, NCH=48, NA=25, DA=15;
 var SG={x:760,y:186,w:430,h:430}; var colW=SG.w/NCH, rowH=SG.h/NA;
 function sx(x){return CX+x;} function sy(y){return CY-y;}

 // phantom (math coords, +x right, +y up)
 var TISS="#9a9486", LUNG="#141414", MED="#c3bcad", BONE="#efe9dd";
 var ph=[
  {x:0,y:0,a:116,b:78,rot:0,mu:0.20,fill:TISS,kind:'body'},
  {x:-52,y:2,a:33,b:51,rot:8,mu:-0.20,fill:LUNG,kind:'lung'},
  {x:52,y:2,a:33,b:51,rot:-8,mu:-0.20,fill:LUNG,kind:'lung'},
  {x:3,y:-2,a:21,b:40,rot:0,mu:0.05,fill:MED,kind:'med'},
  {x:-15,y:9,a:25,b:29,rot:13,mu:0.05,fill:MED,kind:'med'},
  {x:0,y:-55,a:15,b:13,rot:0,mu:0.55,fill:BONE,kind:'bone'},
  {x:0,y:64,a:9,b:6,rot:0,mu:0.26,fill:BONE,kind:'bone'}
 ];
 var ribA=[42,70,110,138,-42,-70,-110,-138];
 for(var r=0;r<ribA.length;r++){var t=ribA[r]*DEG;var rx=0.92*116*Math.cos(t),ry=0.92*78*Math.sin(t);
   ph.push({x:rx,y:ry,a:5,b:12,rot:Math.atan2(ry,rx)/DEG,mu:0.42,fill:BONE,kind:'bone'});}

 // line integral over phantom
 function lineInt(ox,oy,dx,dy){var s=0;
  for(var i=0;i<ph.length;i++){var e=ph[i];
   var c=Math.cos(-e.rot*DEG), sn=Math.sin(-e.rot*DEG);
   var px=ox-e.x, py=oy-e.y;
   var lx=px*c-py*sn, ly=px*sn+py*c;
   var ldx=dx*c-dy*sn, ldy=dx*sn+dy*c;
   var A=ldx*ldx/(e.a*e.a)+ldy*ldy/(e.b*e.b);
   var B=2*(lx*ldx/(e.a*e.a)+ly*ldy/(e.b*e.b));
   var C=lx*lx/(e.a*e.a)+ly*ly/(e.b*e.b)-1;
   var disc=B*B-4*A*C;
   if(disc>0){s+=e.mu*Math.sqrt(disc)/A;}
  }
  return s;
 }

 // sinogram data
 var sino=[];
 for(var k=0;k<NA;k++){var th=k*DA*DEG;var ux=Math.sin(th),uy=Math.cos(th);
  var Sx=RSRC*ux, Sy=RSRC*uy; var d0x=-ux,d0y=-uy; var row=[];
  for(var i=0;i<NCH;i++){var b=-FAN+(i+0.5)*(2*FAN/NCH);var cb=Math.cos(b),sb=Math.sin(b);
   var dx=d0x*cb-d0y*sb, dy=d0x*sb+d0y*cb; var p=lineInt(Sx,Sy,dx,dy); if(p<0)p=0; row.push(p);}
  sino.push(row);
 }
 var flat=[]; for(k=0;k<NA;k++)for(i=0;i<NCH;i++)flat.push(sino[k][i]);
 flat.sort(function(a,b){return a-b;});
 var LO=flat[Math.floor(flat.length*0.34)], HI=flat[Math.floor(flat.length*0.985)];
 if(HI<=LO)HI=LO+1;
 function gray(p){var n=(p-LO)/(HI-LO); if(n<0)n=0; if(n>1)n=1; n=Math.pow(n,0.9); var g=Math.round(255*n); return "rgb("+g+","+g+","+g+")";}

 // orbit
 var gOrbit=D.getElementById('gOrbit');
 put(gOrbit,'circle',{cx:CX,cy:CY,r:RSRC,fill:'none',stroke:'#cfc8b8','stroke-width':1.2,'stroke-dasharray':'4 5',opacity:0.9});
 put(gOrbit,'line',{x1:CX-7,y1:CY,x2:CX+7,y2:CY,stroke:'#9a9486','stroke-width':1.3});
 put(gOrbit,'line',{x1:CX,y1:CY-7,x2:CX,y2:CY+7,stroke:'#9a9486','stroke-width':1.3});

 // phantom
 var gPh=D.getElementById('gPhantom');
 for(i=0;i<ph.length;i++){var e=ph[i];
  var stroke='none', sw=0;
  if(e.kind==='body'){stroke='#6f6a60';sw=1.6;}
  else if(e.kind==='bone'){stroke='#c7c0b0';sw=0.8;}
  var cx=sx(e.x), cy=sy(e.y);
  put(gPh,'ellipse',{cx:cx,cy:cy,rx:e.a,ry:e.b,fill:e.fill,stroke:stroke,'stroke-width':sw,transform:'rotate('+(-e.rot)+' '+cx+' '+cy+')'});
 }

 // anatomy labels
 var gA=D.getElementById('gAnat');
 function lab(x,y,tx,fill,halo,fs){var e=put(gA,'text',{x:x,y:y,'font-size':fs||12.5,fill:fill,'text-anchor':'middle'});
  if(halo){e.setAttribute('paint-order','stroke');e.setAttribute('stroke','#fbf9f4');e.setAttribute('stroke-width',3);e.setAttribute('stroke-linejoin','round');}
  e.textContent=tx;return e;}
 lab(sx(-52),sy(24),'肺野','#f0f0f0',false);
 lab(sx(52),sy(24),'肺野','#f0f0f0',false);
 lab(sx(-4),sy(-3),'縦隔・心臓','#2c2c2c',true);
 lab(sx(0),sy(-55),'椎体','#2c2c2c',true,11.5);
 put(gA,'line',{x1:sx(90),y1:sy(52),x2:sx(72),y2:sy(44),stroke:'#6f6a60','stroke-width':1});
 lab(sx(104),sy(54),'肋骨','#2c2c2c',true);

 // dynamic gantry
 var gBeam=D.getElementById('gBeam');
 var fan=put(gBeam,'polygon',{points:'',fill:'#1b8a86','fill-opacity':0.10,stroke:'#1b8a86','stroke-opacity':0.30,'stroke-width':1.2,'stroke-linejoin':'round'});
 var gRays=D.getElementById('gRays'); var RN=9; var rays=[];
 for(i=0;i<RN;i++){rays.push(put(gRays,'line',{x1:0,y1:0,x2:0,y2:0,stroke:'#1b8a86','stroke-opacity':0.26,'stroke-width':1}));}
 var cray=put(gRays,'line',{x1:0,y1:0,x2:0,y2:0,stroke:'#0c5350','stroke-opacity':0.55,'stroke-width':1.2,'stroke-dasharray':'5 4'});
 var gDB=D.getElementById('gDetBack');
 var detArc=put(gDB,'polyline',{points:'',fill:'none',stroke:'#0c5350','stroke-opacity':0.40,'stroke-width':4,'stroke-linecap':'round'});
 var gDet=D.getElementById('gDetector'); var det=[];
 for(i=0;i<NCH;i++){det.push(put(gDet,'rect',{x:-4.7,y:-4,width:9.4,height:8,rx:1,fill:'#888',stroke:'#5f5f5f','stroke-width':0.4}));}
 var gSrc=D.getElementById('gSource');
 put(gSrc,'rect',{x:-13,y:-10,width:26,height:20,rx:4,fill:'#0c5350',stroke:'#08403d','stroke-width':1});
 put(gSrc,'polygon',{points:'13,-6 25,0 13,6',fill:'#0c5350'});
 put(gSrc,'circle',{cx:13,cy:0,r:2.3,fill:'#ffd79a'});
 var gGL=D.getElementById('gGantryLabels');
 function glab(tx){var e=put(gGL,'text',{'font-size':12.5,'font-weight':600,fill:'#0c5350','text-anchor':'middle','paint-order':'stroke',stroke:'#fbf9f4','stroke-width':3,'stroke-linejoin':'round'});e.textContent=tx;return e;}
 var lblTube=glab('X線管');
 var lblDet=glab('検出器');

 // sinogram cells
 var gS=D.getElementById('gSino'); var cells=[];
 for(k=0;k<NA;k++){var rowC=[];for(i=0;i<NCH;i++){
   var c=put(gS,'rect',{x:(SG.x+i*colW).toFixed(2),y:(SG.y+k*rowH).toFixed(2),width:(colW+0.7).toFixed(2),height:(rowH+0.7).toFixed(2),fill:gray(sino[k][i]),visibility:'hidden'});
   rowC.push(c);}
  cells.push(rowC);}

 // highlight
 var gHi=D.getElementById('gSinoHi');
 var hiBand=put(gHi,'rect',{x:SG.x,y:SG.y,width:SG.w,height:rowH,fill:'#1b8a86','fill-opacity':0.20,stroke:'#0c5350','stroke-width':1.2});
 var rEdge=SG.x+SG.w;
 var hiPtr=put(gHi,'polygon',{points:(rEdge+2)+',-7 '+(rEdge+2)+',7 '+(rEdge-7)+',0',fill:'#0c5350'});
 var hiLbl=put(gHi,'text',{x:rEdge+10,y:0,'font-size':12,'font-weight':700,fill:'#0c5350','text-anchor':'start'});

 // update
 var step=0;
 function update(){
  var th=step*DA*DEG, deg=step*DA;
  var ux=Math.sin(th), uy=Math.cos(th);
  var Sx=RSRC*ux, Sy=RSRC*uy, d0x=-ux, d0y=-uy;
  var Ssx=sx(Sx), Ssy=sy(Sy);
  var pts=[Ssx.toFixed(1)+','+Ssy.toFixed(1)];
  var arcpts=[]; var Dxs=[],Dys=[];
  var rowVals=sino[step];
  for(var i=0;i<NCH;i++){
   var b=-FAN+(i+0.5)*(2*FAN/NCH);var cb=Math.cos(b),sb=Math.sin(b);
   var dx=d0x*cb-d0y*sb, dy=d0x*sb+d0y*cb;
   var Dx=Sx+SDD*dx, Dy=Sy+SDD*dy;
   var Dsx=sx(Dx), Dsy=sy(Dy); Dxs.push(Dsx);Dys.push(Dsy);
   var ang=Math.atan2(-dy,dx)/DEG;
   det[i].setAttribute('transform','translate('+Dsx.toFixed(2)+','+Dsy.toFixed(2)+') rotate('+(ang+90).toFixed(1)+')');
   det[i].setAttribute('fill',gray(rowVals[i]));
   pts.push(Dsx.toFixed(1)+','+Dsy.toFixed(1));
   arcpts.push(Dsx.toFixed(1)+','+Dsy.toFixed(1));
  }
  fan.setAttribute('points',pts.join(' '));
  detArc.setAttribute('points',arcpts.join(' '));
  for(var j=0;j<RN;j++){var idx=Math.round(j*(NCH-1)/(RN-1));
   rays[j].setAttribute('x1',Ssx.toFixed(1));rays[j].setAttribute('y1',Ssy.toFixed(1));
   rays[j].setAttribute('x2',Dxs[idx].toFixed(1));rays[j].setAttribute('y2',Dys[idx].toFixed(1));}
  var Dcx=Sx+SDD*d0x, Dcy=Sy+SDD*d0y;
  cray.setAttribute('x1',Ssx.toFixed(1));cray.setAttribute('y1',Ssy.toFixed(1));
  cray.setAttribute('x2',sx(Dcx).toFixed(1));cray.setAttribute('y2',sy(Dcy).toFixed(1));
  var sang=Math.atan2(-d0y,d0x)/DEG;
  gSrc.setAttribute('transform','translate('+Ssx.toFixed(2)+','+Ssy.toFixed(2)+') rotate('+sang.toFixed(1)+')');
  lblTube.setAttribute('x',(Ssx+26*ux).toFixed(1)); lblTube.setAttribute('y',(Ssy-26*uy+4).toFixed(1));
  var Dcsx=sx(Dcx), Dcsy=sy(Dcy);
  lblDet.setAttribute('x',(Dcsx-28*ux).toFixed(1)); lblDet.setAttribute('y',(Dcsy+28*uy+4).toFixed(1));
  D.getElementById('thetaDisp').textContent='θ = '+deg+'°';
  D.getElementById('stepDisp').textContent='ステップ '+(step+1)+' / '+NA;
  for(var kk=0;kk<NA;kk++){var vis=kk<=step?'visible':'hidden';var rr=cells[kk];for(var ii=0;ii<NCH;ii++)rr[ii].setAttribute('visibility',vis);}
  var ry=SG.y+step*rowH;
  hiBand.setAttribute('y',ry.toFixed(2));
  hiPtr.setAttribute('transform','translate(0,'+(ry+rowH/2).toFixed(2)+')');
  hiLbl.setAttribute('y',(ry+rowH/2+4).toFixed(2));
  hiLbl.textContent='θ='+deg+'°';
 }

 function next(){step=(step+1)%NA;update();}
 var stage=D.getElementById('stage');
 stage.addEventListener('click',next);
 window.addEventListener('keydown',function(ev){var kk=ev.key;if(kk===' '||kk==='Enter'||kk==='ArrowRight'||kk==='ArrowUp'||kk==='ArrowDown'){ev.preventDefault();next();}});
 update();
})();
//
